        ops = s.split()
        queue = deque()
        seen = set()
        for op in ops:
            if op == "enqueue":
                val = 0
                i = ops.index(op) + 1
                while i < len(ops) and ops[i] != "dequeue":
                    val = val * 10 + int(ops[i])
                    i += 1
                queue.append(val)
                seen.add(val)
            elif op == "dequeue":
                if queue:
                    seen.remove(queue.popleft())
        for val in seen:
            return val
        return -1

