#include <iostream>
#include <queue>
#include <string>
using namespace std;

class Solution {
public:
    int getFirstRepeated(string s) {
        queue<int> queue;
        set<int> seen;
        string op;
        int val = 0;
        size_t i = 0;
        while (i < s.length()) {
            if (s[i] != ' ') {
                op += s[i];
                i++;
            }
            else {
                string arg;
                while (i < s.length() && s[i] != ' ') {
                    arg += s[i];
                    i++;
                }
                if (op == "enqueue") {
                    queue.push_back(stoi(arg));
                    seen.insert(queue.back());
                }
                else if (op == "dequeue") {
                    if (!queue.empty()) {
                        seen.erase(queue.front());
                        queue.pop_front();
                    }
                }
                op.clear();
            }
        }
        for (int val : seen) {
            return val;
        }
        return -1;
    }
};

int main() {
    string s;
    getline(cin, s);
    Solution solution;
    cout << solution.getFirstRepeated(s) << endl;
    return 0;
}
